                    :disabled="selectedRecipe._favLoading"
                    @click="toggleFavorite(selectedRecipe)">
              {{ selectedRecipe._favLoading ? '…' : (selectedRecipe.isFavorited ? '♥ Saved' : '♥ Save') }}
            </button>
            <button v-if="!isProfessional" class="btn fw-semibold flex-fill"
                    style="background:#f3f4f6;color:#1b4d1b;border:none;padding:0.5rem 0.875rem;border-radius:8px;font-size:0.875rem;"
                    @click="pickMeal(selectedRecipe)">Add to Diary</button>
            <button class="btn fw-semibold w-100"
                    style="border:none;padding:0.5rem 0.875rem;border-radius:8px;font-size:0.875rem;"
                    :style="selectedRecipe.isUsed ? 'background:#2e7d32;color:#fff;' : 'background:#f3f4f6;color:#1b4d1b;'"
                    :disabled="selectedRecipe._usedLoading"
                    @click="toggleUsed(selectedRecipe)">
              {{ selectedRecipe._usedLoading ? '…' : (selectedRecipe.isUsed ? '✓ Used It' : 'Mark as Used') }}
            </button>
          </div>

          <div class="p-3 rounded" style="background:#f9fafb;border:1px solid #e5e7eb;">
            <h6 class="fw-semibold mb-2" style="color:#1b4d1b;font-size:0.875rem;">Nutrition Per Serving</h6>
