              <div class="d-flex justify-content-between py-1" style="border-bottom:1px solid #f3f4f6;">
                <span>Calories</span><span class="fw-semibold" style="color:#1b4d1b;">{{ selectedRecipe.kcal }} kcal</span>
              </div>
