              <div v-if="selectedRecipe.sugars != null" class="d-flex justify-content-between py-1 ps-2" style="border-bottom:1px solid #f3f4f6;">
                <span style="font-size:0.75rem;">of which sugars</span><span class="fw-semibold" style="color:#1b4d1b;font-size:0.75rem;">{{ selectedRecipe.sugars }}g</span>
              </div>
              <div class="d-flex justify-content-between py-1" style="border-bottom:1px solid #f3f4f6;">
                <span>Fat</span><span class="fw-semibold" style="color:#1b4d1b;">{{ selectedRecipe.fat }}g</span>
              </div>
              <div v-if="selectedRecipe.saturatedFat != null" class="d-flex justify-content-between py-1 ps-2" style="border-bottom:1px solid #f3f4f6;">
                <span style="font-size:0.75rem;">of which saturated</span><span class="fw-semibold" style="color:#1b4d1b;font-size:0.75rem;">{{ selectedRecipe.saturatedFat }}g</span>
              </div>
              <div v-if="selectedRecipe.fibre != null" class="d-flex justify-content-between py-1" style="border-bottom:1px solid #f3f4f6;">
