        <div class="col-md-4">
          <h6 class="fw-semibold mb-3" style="color:#1b4d1b;font-size:0.9375rem;">
            Reviews
            <span v-if="selectedRecipe.averageRating != null" class="ms-2 fw-normal" style="font-size:0.8125rem;color:#6b7280;">
              ★ {{ selectedRecipe.averageRating.toFixed(1) }} ({{ selectedRecipe.reviewCount }})
            </span>
          </h6>

          <div v-if="(selectedRecipe.reviews ?? []).length > 0" class="mb-4" style="max-height:340px;overflow-y:auto;">
            <div v-for="rev in selectedRecipe.reviews" :key="rev.reviewId"
                 class="p-3 mb-2 rounded" style="background:#f9fafb;border:1px solid #e5e7eb;">
              <div class="d-flex justify-content-between align-items-center mb-1">
                <span style="color:#fbbf24;font-size:0.875rem;">{{ '★'.repeat(rev.rating) }}{{ '☆'.repeat(5 - rev.rating) }}</span>
                <small style="color:#9ca3af;font-size:0.75rem;">{{ formatDate(rev.createdAt) }}</small>
              </div>
              <div v-if="rev.comment" style="font-size:0.875rem;color:#6b7280;">{{ rev.comment }}</div>
            </div>
          </div>
          <div v-else class="mb-4" style="color:#9ca3af;font-size:0.875rem;">No reviews yet — be the first!</div>

          <div v-if="!userReviewExists">
            <div class="p-3 rounded" style="background:#f9fafb;border:1px solid #e5e7eb;">
              <div class="d-flex align-items-center gap-2 mb-2">
                <span class="fw-semibold" style="font-size:0.875rem;color:#1b4d1b;">Rate this recipe:</span>
                <span v-for="star in 5" :key="star"
                      style="cursor:pointer;font-size:1.25rem;"
                      :style="star <= reviewDraft.rating ? 'color:#fbbf24;' : 'color:#d1d5db;'"
                      @click="reviewDraft.rating = star">★</span>
              </div>
              <textarea class="form-control mb-2" rows="2"
                        placeholder="Leave a comment (optional)…"
                        v-model="reviewDraft.comment"
                        style="border:1px solid #d4e7d4;border-radius:8px;padding:0.5rem 0.75rem;font-size:0.875rem;resize:none;"></textarea>
              <div v-if="reviewError" class="mb-2" style="color:#d94f4f;font-size:0.875rem;">{{ reviewError }}</div>
              <button class="btn fw-semibold w-100"
                      style="background:#1b4d1b;color:#fff;border:none;padding:0.5rem 1rem;border-radius:8px;font-size:0.875rem;"
                      :disabled="reviewDraft.rating === 0 || reviewSubmitting"
                      @click="submitReview">
                {{ reviewSubmitting ? 'Submitting…' : 'Submit Review' }}
              </button>
            </div>
          </div>
          <div v-else class="p-3 rounded" style="background:#f9fafb;border:1px solid #e5e7eb;color:#9ca3af;font-size:0.875rem;">
            You have already reviewed this recipe.
          </div>
        </div>

      </div>
    </div>

    <Teleport to="body">
      <div v-if="pendingRecipe"
           style="position:fixed;inset:0;background:rgba(0,0,0,0.45);z-index:1050;display:flex;align-items:center;justify-content:center;"
           @click.self="pendingRecipe = null">
        <div class="p-4 rounded bg-white" style="min-width:300px;max-width:380px;border-radius:12px;box-shadow:0 8px 24px rgba(0,0,0,0.15);">
          <h6 class="fw-semibold mb-1" style="color:#1b4d1b;">Add to Diary</h6>
          <p class="mb-3" style="color:#6b7280;font-size:0.875rem;">{{ pendingRecipe.title }} — choose a meal:</p>
          <div class="d-grid gap-2">
            <button v-for="meal in MEAL_OPTIONS" :key="meal.id"
                    class="btn fw-semibold"
                    style="background:#1b4d1b;color:#fff;border:none;padding:0.625rem;border-radius:8px;font-size:0.9375rem;"
                    @click="confirmAdd(meal.id)">
              {{ meal.label }}
            </button>
          </div>
          <button class="btn w-100 mt-3"
                  style="background:#f3f4f6;color:#6b7280;border:none;padding:0.5rem;border-radius:8px;font-size:0.875rem;"
                  @click="pendingRecipe = null">Cancel</button>
        </div>
      </div>
    </Teleport>

  </div>
</template>

<script setup>
import { ref, computed, onMounted, nextTick, watch } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { apiFetch, currentUser } from '../auth.js'
import { addRecipeToDiary } from '../diaryStore.js'

const isProfessional = computed(() => currentUser.value.role === 'professional')

const route = useRoute()
const router = useRouter()

const PAGE_SIZE = 6

const MEAL_OPTIONS = [
  { id: 'breakfast', label: 'Breakfast' },
  { id: 'lunch', label: 'Lunch' },
  { id: 'dinner', label: 'Dinner' },
  { id: 'snack', label: 'Snacks & Drinks' },
]

const recipes = ref([])
const loading = ref(true)
const loadError = ref('')

const searchQuery = ref('')
const cuisineFilter = ref('')
const categoryFilter = ref('')
const ingredientFilter = ref('')
const activeTab = ref('all')
const currentPage = ref(1)
const selectedRecipe = ref(null)
const pendingRecipe = ref(null)

const reviewDraft = ref({ rating: 0, comment: '' })
const reviewSubmitting = ref(false)
const reviewError = ref('')

const tabs = [
  { id: 'all', label: 'All Recipes' },
  { id: 'fav', label: 'My Favourites' },
  { id: 'used', label: 'I Used It' },
]

onMounted(loadRecipes)

async function loadRecipes() {
  loading.value = true
  loadError.value = ''
  try {
    const res = await apiFetch('/api/recipes')
    const data = await res.json().catch(() => ({}))
    if (!res.ok) {
      loadError.value = data.error || 'Failed to load recipes'
      return
    }
    recipes.value = (data.recipes ?? []).map(r => ({ ...r, _favLoading: false, _usedLoading: false }))
    await handleHighlight()
    await handleRouteRecipeId()
  } catch {
    loadError.value = 'Network error — could not load recipes'
  } finally {
    loading.value = false
  }
}

async function handleRouteRecipeId() {
  const id = Number(route.params.id)
  if (!id) return
  const recipe = recipes.value.find(r => r.recipeId === id)
  if (recipe) {
    await viewRecipe(recipe)
  }
}

async function handleHighlight() {
  const id = Number(route.query.highlight)
  if (!id) return
  const idx = recipes.value.findIndex(r => r.recipeId === id)
  if (idx === -1) return
  // Jump to the page that contains this recipe
  currentPage.value = Math.floor(idx / PAGE_SIZE) + 1
  await nextTick()
  const recipe = recipes.value[idx]
  selectedRecipe.value = recipe
  reviewDraft.value = { rating: 0, comment: '' }
  reviewError.value = ''
  await nextTick()
  document.getElementById('recipe-detail')?.scrollIntoView({ behavior: 'smooth', block: 'start' })
}

async function loadFavorites() {
  loading.value = true
  loadError.value = ''
  try {
    const res = await apiFetch('/api/recipes/favorites')
    const data = await res.json().catch(() => ({}))
    if (!res.ok) {
      loadError.value = data.error || 'Failed to load favourites'
      return
    }
    recipes.value = (data.recipes ?? []).map(r => ({ ...r, isFavorited: true, _favLoading: false, _usedLoading: false }))
  } catch {
    loadError.value = 'Network error — could not load favourites'
  } finally {
    loading.value = false
  }
}

async function loadUsed() {
  loading.value = true
  loadError.value = ''
  try {
    const res = await apiFetch('/api/recipes/used')
    const data = await res.json().catch(() => ({}))
    if (!res.ok) {
      loadError.value = data.error || 'Failed to load used recipes'
      return
    }
    recipes.value = (data.recipes ?? []).map(r => ({ ...r, isUsed: true, _favLoading: false, _usedLoading: false }))
  } catch {
    loadError.value = 'Network error — could not load used recipes'
  } finally {
    loading.value = false
  }
}

function switchTab(tabId) {
  activeTab.value = tabId
  currentPage.value = 1
  selectedRecipe.value = null
  cuisineFilter.value = ''
  categoryFilter.value = ''
  ingredientFilter.value = ''
  if (tabId === 'fav') loadFavorites()
  else if (tabId === 'used') loadUsed()
  else loadRecipes()
}

const availableCuisines = computed(() => {
  const seen = new Set()
  for (const r of recipes.value) {
    if (r.cuisine) seen.add(r.cuisine)
  }
  return [...seen].sort()
})

const availableCategories = computed(() => {
  const seen = new Set()
  for (const r of recipes.value) {
    if (r.category) seen.add(r.category)
  }
  return [...seen].sort()
})

const hasActiveFilters = computed(() =>
  cuisineFilter.value !== '' || categoryFilter.value !== '' || ingredientFilter.value.trim() !== ''
)

const filteredRecipes = computed(() => {
  let result = recipes.value
  if (searchQuery.value) {
    const q = searchQuery.value.toLowerCase()
    result = result.filter(r => r.title.toLowerCase().includes(q))
  }
  if (cuisineFilter.value) {
    result = result.filter(r => r.cuisine === cuisineFilter.value)
  }
  if (categoryFilter.value) {
    result = result.filter(r => r.category === categoryFilter.value)
  }
  if (ingredientFilter.value.trim()) {
    const q = ingredientFilter.value.trim().toLowerCase()
    result = result.filter(r =>
      (r.ingredientDetails ?? []).some(ing => ing.name.toLowerCase().includes(q))
    )
  }
  return result
})

const totalPages = computed(() => Math.max(1, Math.ceil(filteredRecipes.value.length / PAGE_SIZE)))

const pagedRecipes = computed(() => {
  const start = (currentPage.value - 1) * PAGE_SIZE
  return filteredRecipes.value.slice(start, start + PAGE_SIZE)
})

const pageItems = computed(() => {
  const total = totalPages.value
  const cur = currentPage.value
  const items = []
  for (let p = 1; p <= total; p++) {
    if (p === 1 || p === total || (p >= cur - 1 && p <= cur + 1)) {
      items.push(p)
    } else if (items[items.length - 1] !== '...') {
      items.push('...')
    }
  }
  return items
})

const selectedRecipeSteps = computed(() => {
  if (!selectedRecipe.value?.instructions) return []
  return selectedRecipe.value.instructions.split(/\n+/).filter(s => s.trim())
})

const userReviewExists = computed(() => {
  if (!selectedRecipe.value) return false
  const uid = currentUser.value.userId
  return (selectedRecipe.value.reviews ?? []).some(r => r.subscriberId === uid)
})

async function viewRecipe(recipe) {
  selectedRecipe.value = recipe
  reviewDraft.value = { rating: 0, comment: '' }
  reviewError.value = ''

  // Update URL with recipe ID
  router.push({ path: `/recipes/${recipe.recipeId}`, hash: '#recipe-detail' })

  await nextTick()
  document.getElementById('recipe-detail')?.scrollIntoView({ behavior: 'smooth', block: 'start' })
}

function closeRecipe() {
  selectedRecipe.value = null
  // Clear the recipe ID from URL
  router.push('/recipes')
}

// Watch for route changes (e.g., back button)
watch(() => route.params.id, (newId) => {
  if (!newId && selectedRecipe.value) {
    // URL changed to /recipes (no ID), close the recipe detail
    selectedRecipe.value = null
  } else if (newId && recipes.value.length > 0) {
    // URL has a recipe ID, open that recipe
    const recipe = recipes.value.find(r => r.recipeId === Number(newId))
    if (recipe && (!selectedRecipe.value || selectedRecipe.value.recipeId !== recipe.recipeId)) {
      selectedRecipe.value = recipe
      reviewDraft.value = { rating: 0, comment: '' }
      reviewError.value = ''
      nextTick(() => {
        document.getElementById('recipe-detail')?.scrollIntoView({ behavior: 'smooth', block: 'start' })
      })
    }
  }
})

function pickMeal(recipe) {
  pendingRecipe.value = recipe
}

async function confirmAdd(mealId) {
  try {
    await addRecipeToDiary(pendingRecipe.value, mealId)
  } catch (e) {
    alert(e.message)
  } finally {
    pendingRecipe.value = null
  }
}

async function toggleFavorite(recipe) {
  if (recipe._favLoading) return
  recipe._favLoading = true
  try {
    const res = await apiFetch(`/api/recipes/${recipe.recipeId}/favorite`, { method: 'POST' })
    const data = await res.json().catch(() => ({}))
    if (!res.ok) {
      alert(data.error || 'Failed to update favourite')
      return
    }
    recipe.isFavorited = data.favorite?.favorited ?? !recipe.isFavorited
    if (selectedRecipe.value?.recipeId === recipe.recipeId) {
      selectedRecipe.value.isFavorited = recipe.isFavorited
    }
    // If on favourites tab and unfavorited, remove from list
    if (activeTab.value === 'fav' && !recipe.isFavorited) {
      recipes.value = recipes.value.filter(r => r.recipeId !== recipe.recipeId)
    }
  } catch {
    alert('Network error — could not update favourite')
  } finally {
    recipe._favLoading = false
  }
}

async function toggleUsed(recipe) {
  if (recipe._usedLoading) return
  recipe._usedLoading = true
  try {
    const res = await apiFetch(`/api/recipes/${recipe.recipeId}/usage`, { method: 'POST' })
    const data = await res.json().catch(() => ({}))
    if (!res.ok) {
      alert(data.error || 'Failed to update usage')
      return
    }
    recipe.isUsed = data.usage?.used ?? !recipe.isUsed
    if (selectedRecipe.value?.recipeId === recipe.recipeId) {
      selectedRecipe.value.isUsed = recipe.isUsed
    }
    // If on used tab and unmarked, remove from list
    if (activeTab.value === 'used' && !recipe.isUsed) {
      recipes.value = recipes.value.filter(r => r.recipeId !== recipe.recipeId)
    }
  } catch {
    alert('Network error — could not update usage')
  } finally {
    recipe._usedLoading = false
  }
}

async function submitReview() {
  if (reviewDraft.value.rating === 0) return
  reviewError.value = ''
  reviewSubmitting.value = true
  try {
    const res = await apiFetch(`/api/recipes/${selectedRecipe.value.recipeId}/reviews`, {
      method: 'POST',
      body: JSON.stringify({
        rating: reviewDraft.value.rating,
        comment: reviewDraft.value.comment.trim() || null,
      }),
    })
    const data = await res.json().catch(() => ({}))
    if (!res.ok) {
      reviewError.value = data.error || 'Failed to submit review'
      return
    }
    const newReview = data.review
    selectedRecipe.value.reviews = [newReview, ...(selectedRecipe.value.reviews ?? [])]
    const ratings = selectedRecipe.value.reviews.map(r => r.rating)
    selectedRecipe.value.averageRating = ratings.reduce((a, b) => a + b, 0) / ratings.length
    selectedRecipe.value.reviewCount = ratings.length
    // Sync back into main list
    const listEntry = recipes.value.find(r => r.recipeId === selectedRecipe.value.recipeId)
    if (listEntry) {
      listEntry.averageRating = selectedRecipe.value.averageRating
      listEntry.reviewCount = selectedRecipe.value.reviewCount
    }
    reviewDraft.value = { rating: 0, comment: '' }
  } catch {
    reviewError.value = 'Network error'
  } finally {
    reviewSubmitting.value = false
  }
}

function formatDate(value) {
  if (!value) return ''
  return new Date(value).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' })
}
</script>


